#include <bits/stdc++.h>using namespace std;typedef long long ll;ll dynamic(ll i,ll turn,vector<ll> &a,vector<vector<ll>> &dp){    if(i>=a.size())return 0;    if(dp[i][turn]!=-1)return dp[i][turn];    if(turn==0){        ll one=a[i]+dynamic(i+1,1,a,dp);        if(i+1>=a.size()){            return dp[i][turn]=one;        }        ll two=a[i]+a[i+1]+dynamic(i+2,1,a,dp);        return dp[i][turn]=min(one,two);    }    else{        ll one=dynamic(i+1,0,a,dp);        if(i+1>=a.size()){            return dp[i][turn]=one;        }        ll two=dynamic(i+2,0,a,dp);        return dp[i][turn]=min(one,two);    }}int main(){    ll t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n,0);        ll cnt=0;        for(int i=0;i<n;i++){            cin>>a[i];        }        vector<vector<ll>> dp(n,vector<ll>(2,-1));        // cout<<"ans=";        cout<<dynamic(0,0,a,dp)<<endl;    }}